BEGIN;

-- Remove partial-color styled blocks from survival / ear training tutorial scripts.

UPDATE public.survival_tutorial_scripts
SET
  script = jsonb_set(
    jsonb_set(
      jsonb_set(script, '{steps,25,introCharacter}', '{"ja":"まずはDm7。下からCとF、2音だけ。","en":"First, Dm7. Just C and F from the bottom."}'::jsonb, true),
      '{steps,26,introCharacter}',
      '{"ja":"次はG7。下からBとF。","en":"Next, G7. B and F from the bottom."}'::jsonb,
      true
    ),
    '{steps,27,introCharacter}',
    '{"ja":"最後はCM7。下からBとEで着地しよう。","en":"Last, CM7. Land on B and E from the bottom."}'::jsonb,
    true
  ),
  updated_at = now()
WHERE id = 'onboarding-v1';

